module top_module(input wire button,input wire clk,input wire res,output wire clk_div);reg [3 : 0] flip_flop; 
  assign clk_div = &flip_flop; 
  always @(posedge clk) begin 
  if(res) 
  flip_flop <= 4'b0; 
  else begin 
  flip_flop[0] <= button; 
  flip_flop[1] <= flip_flop[0]; 
  flip_flop[2] <= flip_flop[1]; 
  flip_flop[3] <= flip_flop[2]; 
  end 
  end 
 endmodule
